#include <iostream>

using namespace std;

class BankAccount
{
private:
    double balance;

public:
    BankAccount()
    {
        balance = 0;
    }

    void deposit(double amount)
    {
        if (amount > 0)
        {
            balance += amount;
        }
    }

    void withdraw(double amount)
    {
        if (amount > 0 && amount <= balance) // enforce the rule: never go negative
        {
            balance -= amount;
        }
        else
        {
            cout << "Withdrawal denied." << endl;
        }
    }

    double getBalance()
    {
        return balance;
    }
};

int main()
{
    BankAccount acc;
    acc.deposit(500);
    acc.withdraw(1000); // more than the balance

    cout << acc.getBalance() << endl;

    return 0;
}

